class AuthorInputType(sgqlc.types.Input):
    __schema__ = schema
    __field_names__ = ('alias_id', 'bio', 'born_date', 'born_year', 'curation_status', 'death_date', 'death_year', 'gender_id', 'id', 'image_id', 'is_bipoc', 'is_lgbtq', 'location', 'locked', 'name', 'name_personal', 'slug')
    alias_id = sgqlc.types.Field(Int, graphql_name='alias_id')
    bio = sgqlc.types.Field(String, graphql_name='bio')
    born_date = sgqlc.types.Field(date, graphql_name='born_date')
    born_year = sgqlc.types.Field(Int, graphql_name='born_year')
    curation_status = sgqlc.types.Field(String, graphql_name='curation_status')
    death_date = sgqlc.types.Field(date, graphql_name='death_date')
    death_year = sgqlc.types.Field(Int, graphql_name='death_year')
    gender_id = sgqlc.types.Field(Int, graphql_name='gender_id')
    id = sgqlc.types.Field(Int, graphql_name='id')
    image_id = sgqlc.types.Field(Int, graphql_name='image_id')
    is_bipoc = sgqlc.types.Field(Boolean, graphql_name='is_bipoc')
    is_lgbtq = sgqlc.types.Field(Boolean, graphql_name='is_lgbtq')
    location = sgqlc.types.Field(String, graphql_name='location')
